import sys
input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    grid = []
    lab = None
    for i in range(n):
        row = input().strip()
        grid.append(list(row))
        for j in range(len(row)):
            if row[j] == 'L':
                lab = (i, j)

    dirs = [(-1,0),(1,0),(0,-1),(0,1)]

    cnt = [[0]*m for _ in range(n)]
    for i in range(n):
        for j in range(m):
            if grid[i][j] != '#':
                c = 0
                for di, dj in dirs:
                    ni, nj = i+di, j+dj
                    if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                        c += 1
                cnt[i][j] = c

    forceable = [[False]*m for _ in range(n)]
    queue = deque()
    li, lj = lab
    forceable[li][lj] = True
    queue.append((li, lj))

    while queue:
        i, j = queue.popleft()
        for di, dj in dirs:
            ni, nj = i+di, j+dj
            if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#' and not forceable[ni][nj]:
                cnt[ni][nj] -= 1
                if cnt[ni][nj] <= 1:
                    forceable[ni][nj] = True
                    queue.append((ni, nj))

    out = []
    for i in range(n):
        row = []
        for j in range(m):
            if grid[i][j] == '.' and forceable[i][j]:
                row.append('+')
            else:
                row.append(grid[i][j])
        out.append(''.join(row))
    print('\n'.join(out))

t = int(input())
for _ in range(t):
    solve()

